import { moduleMetadata } from '@storybook/angular';
import { ButtonComponent } from './button.component';
import { IconComponent } from '../icon/icon.component';
const meta = {
    title: 'components/Button',
    component: ButtonComponent,
    tags: ['autodocs'],
    decorators: [
        moduleMetadata({
            imports: [IconComponent],
        }),
    ],
    argTypes: {
        type: {
            control: 'select',
            options: ['primary', 'secondary', 'tertiary', 'toned', 'link'],
        },
        state: {
            control: 'select',
            options: ['default', 'disabled', 'pressed', 'error', 'success', 'loading'],
        },
        size: {
            control: 'select',
            options: ['large', 'medium', 'small'],
        },
        buttonText: {
            control: 'boolean',
        },
        showLeftIcon: {
            control: 'boolean',
        },
        showRightIcon: {
            control: 'boolean',
        },
        leftIconName: {
            control: 'text',
        },
        rightIconName: {
            control: 'text',
        },
    },
    args: {
        label: 'Button',
        type: 'primary',
        state: 'default',
        size: 'large',
        buttonText: true,
        showLeftIcon: false,
        showRightIcon: false,
        leftIconName: 'icon-add',
        rightIconName: 'icon-add',
    },
};
export default meta;
export const Primary = {
    args: {
        label: 'Button',
        showLeftIcon: true,
        showRightIcon: true,
        leftIconName: 'icon-add',
        rightIconName: 'icon-add',
    },
};
export const Disabled = {
    args: {
        label: 'Button',
        state: 'disabled',
        showLeftIcon: true,
        showRightIcon: true,
    },
};
export const Loading = {
    args: {
        label: 'Loading...',
        state: 'loading',
    },
};
export const Success = {
    args: {
        label: 'Success',
        state: 'success',
    },
};
export const Error = {
    args: {
        label: 'Error',
        state: 'error',
    },
};
export const WithIconsOnly = {
    args: {
        buttonText: false,
        showLeftIcon: true,
        showRightIcon: true,
    },
};
export const NoIcons = {
    args: {
        buttonText: true,
        showLeftIcon: false,
        showRightIcon: false,
    },
};
export const OnState = {
    args: {
        label: 'Button',
        showLeftIcon: true,
        showRightIcon: true,
        type: 'primary',
    },
};
export const OffState = {
    args: {
        label: 'Button',
        showLeftIcon: true,
        showRightIcon: true,
        type: 'primary',
    },
};
export const SmallSize = {
    args: {
        label: 'Button',
        size: 'small',
        showLeftIcon: true,
        showRightIcon: true,
    },
};
export const MediumSize = {
    args: {
        label: 'Button',
        size: 'medium',
        showLeftIcon: true,
        showRightIcon: true,
    },
};
export const LargeSize = {
    args: {
        label: 'Button',
        size: 'large',
        showLeftIcon: true,
        showRightIcon: true,
    },
};
export const Toned = {
    args: {
        label: 'Button',
        type: 'toned',
        showLeftIcon: false,
        showRightIcon: true,
    },
};
